// Prepare nutrition data for AI analysis
const userData = $input.all();
const nutritionReports = [];

for (const user of userData) {
  const data = user.json;

  // Calculate macro percentages
  const caloriePercentage = (data.total_calories / data.daily_calorie_target) * 100;
  const proteinPercentage = (data.total_protein / data.daily_protein_target) * 100;
  const carbsPercentage = (data.total_carbs / data.daily_carbs_target) * 100;
  const fatPercentage = (data.total_fat / data.daily_fat_target) * 100;

  // Determine performance level
  let performanceLevel = 'Excellent';
  if (caloriePercentage < 60) performanceLevel = 'Needs Improvement';
  else if (caloriePercentage < 80) performanceLevel = 'Good';
  else if (caloriePercentage > 120) performanceLevel = 'Exceeded';

  const nutritionReport = {
    user_id: data.id,
    email: data.email,
    name: data.name,
    date: new Date().toLocaleDateString(),
    performance: {
      level: performanceLevel,
      calorie_percentage: Math.round(caloriePercentage),
      protein_percentage: Math.round(proteinPercentage),
      carbs_percentage: Math.round(carbsPercentage),
      fat_percentage: Math.round(fatPercentage)
    },
    targets: {
      calories: data.daily_calorie_target,
      protein: data.daily_protein_target,
      carbs: data.daily_carbs_target,
      fat: data.daily_fat_target
    },
    actuals: {
      calories: data.total_calories,
      protein: data.total_protein,
      carbs: data.total_carbs,
      fat: data.total_fat,
      meals_logged: data.meals_logged || 0,
      water_intake_ml: data.water_intake || 0
    },
    hydration: {
      intake_ml: data.water_intake || 0,
      goal_ml: 2000,
      percentage: Math.round(((data.water_intake || 0) / 2000) * 100)
    }
  };

  nutritionReports.push(nutritionReport);
}

return nutritionReports.map(report => ({ json: report }));

// Process AI response and prepare email content
const aiResponses = $input.all();
const emailContents = [];

for (const response of aiResponses) {
  const userData = response.json;
  const aiAnalysis = JSON.parse(response.json.message.content);

  // Create email content with AI insights
  const emailContent = {
    user_id: userData.user_id,
    email: userData.email,
    name: userData.name,
    date: userData.date,
    performance: userData.performance,
    targets: userData.targets,
    actuals: userData.actuals,
    hydration: userData.hydration,
    ai_insights: aiAnalysis,
    email_subject: `\ud83e\udd57 AI Nutrition Report - ${userData.name} - ${userData.date}`,
    emoji: userData.performance.level === 'Excellent' ? '\ud83c\udf89' : userData.performance.level === 'Good' ? '\ud83d\udc4d' : userData.performance.level === 'Needs Improvement' ? '\ud83d\udcaa' : '\u26a0\ufe0f'
  };

  emailContents.push(emailContent);
}

return emailContents.map(content => ({ json: content }));
